  <div class="container">
    <!-- HEADER -->
    <div class="header">
      <div class="header-content">
        <h1>XÁC NHẬN ĐẶT PHÒNG</h1>
        <div class="hotel-name">{{hotel.localName}} - {{hotel.star}} SAO</div>
        <div class="hotel-address">
          {{hotel.address}}
        </div>
      </div>

      <img class="header-image" src="https://i.ibb.co/DDqDq3HT/Layer-9-1-4.png" alt="icon-bgt" />
    </div>

    <!-- ORDER INFO -->
    <div class="box">
      <div class="row">
        <div class="col">
          <div class="orderContainer">
            <div class="label">Mã Đơn Hàng</div>
            <div class="value">{{code}}</div>
          </div>
          <div class="orderContainer">
            <div class="label">Mã Nhận Phòng</div>
            <div class="value">{{#if externalCode}}{{externalCode}}{{else}}Đang cập nhật{{/if}}</div>
          </div>
          <div class="orderContainer">
            <div class="label">Nhận Phòng</div>
            <div class="value">{{formatDate checkInDate "dddd - DD/MM/YYYY"}} · Sau
              {{hotel.checkInHouse}}</div>
          </div>
          <div class="orderContainer">
            <div class="label">Trả Phòng</div>
            <div class="value">{{formatDate checkOutDate "dddd - DD/MM/YYYY"}} · Trước {{hotel.checkOutHouse}}</div>
          </div>
        </div>

        <div class="col">
          <div class="orderContainer">
            <div class="label">Giá trị đơn hàng</div>
            <div class="price">{{formatCurrency netTotal}} VND</div>
          </div>
          <div class="badge">{{#gte agentPaidAmount agentToBePaidAmount}}ĐÃ THANH TOÁN{{else}}CHƯA THANH TOÁN{{/gte}}
          </div>
          <div class="valueNotBold">({{nights}} đêm)</div>
          <div class="valueNotBold">
            {{formatNumber guest.totalRooms "00"}} Phòng{{#if guest.adults}} - {{formatNumber guest.adults "00"}} Người
            Lớn{{/if}}{{#if guest.children}} - {{formatNumber guest.children "00"}} Trẻ Em{{/if}}
          </div>
        </div>
      </div>

      <hr class="stroke" />

      <!-- GUEST & REQUEST -->
      <div class="row guest-containter">
        <div class="col">
          <div class="section-title">Danh Sách Khách Lưu Trú</div>

          {{#each bookingRooms}}
          <div class="guest-box">
            <div class="label-guest">Phòng {{sum @index 1}}</div>
            <div class="value-guest">
              {{#each this.customers}}
              {{#if this.gender}}{{#eq this.gender "MALE"}}Ông{{/eq}}{{#eq this.gender "FEMALE"}}Bà{{/eq}}{{/if}}
              {{this.firstName}} {{this.lastName}}{{#unless @last}}<br />{{/unless}}
              {{/each}}
            </div>
          </div>
          {{/each}}
        </div>

        <div class="col">
          <div class="section-title">Yêu Cầu Khác</div>
          <div class="request-box">{{#if agNote}}{{agNote}}{{else}}Không có yêu cầu đặc biệt{{/if}}</div>
          <div class="request-note">
            (Yêu cầu của quý khách được gửi đến khách sạn, tuy nhiên sẽ không
            được đảm bảo vì phụ thuộc tình trạng sẵn có của khách sạn)
          </div>
        </div>
      </div>

      <hr class="stroke" />

      <!-- SERVICE -->
      <div class="section-title">Dịch Vụ Chi Tiết</div>
      <table>
        <thead>
          <tr>
            <th>Dịch vụ</th>
            <th>Khuyến mãi</th>
            <th>Đơn giá</th>
            <th>Số lượng</th>
            <th>Thành tiền</th>
          </tr>
        </thead>
        <tbody>
          {{#each bookingRooms}}
          <tr>
            <td>{{this.room.localName}}{{#if this.stayDates.0.priceSetting.mealPlan}} -
              {{this.stayDates.0.priceSetting.mealPlan}}{{/if}}</td>
            <td>{{#if this.promotions.0.promotionName}}{{this.promotions.0.promotionName}}{{else}}-{{/if}}</td>
            <td>{{formatCurrency this.stayDates.0.baseRate}}</td>
            <td>{{formatNumber ../guest.totalRooms "00"}} phòng</td>
            <td>{{formatCurrency this.netTotal}}</td>
          </tr>
          {{#if this.surcharges}}
          {{#each this.surcharges}}
          <tr>
            <td>{{this.surchargeName}}</td>
            <td>-</td>
            <td>{{formatCurrency this.surchargeRate}}</td>
            <td>01 khách</td>
            <td>{{formatCurrency this.surchargeRate}}</td>
          </tr>
          {{/each}}
          {{/if}}
          {{/each}}
        </tbody>
      </table>

      <div class="table-note">
        (Giá phòng đã bao gồm dịch vụ lưu trú, phụ phí nếu có, thuế VAT và phí
        dịch vụ)
      </div>
    </div>

    <!-- CANCEL POLICY -->
    <div class="policy">
      <div class="section-title">Chính Sách Huỷ Phòng</div>
