export const resolveFeeNote = (cancellationOption, checkInDate, options = {}) => {
  const opts = {
    shortText: false, // text ngắn gọn
    templateTicket: false, // hiển thị cho xác nhận đặt phòng
    ...options,
  }
  const {
    condition, cancellationPeriod, cancellationPeriodUnitTime, amount, unitType,
  } = cancellationOption || {}
  if (!condition) return []
  const notes = []
  const netTotal = formatCurrency(cancellationOption.netTotal || cancellationOption.price * (cancellationOption.stayDatesLength || 1) || 0) || ''
  const time = cancellationPeriod >= 1
    ? `${cancellationPeriod} ${cancellationPeriodUnitTime === 'HOUR' ? 'giờ' : 'ngày'}`
    : ''
  const checkinDateFormatted = checkInDate
    ? moment(checkInDate).format('dddd, DD/MM/YYYY')
    : ''
  const date = moment(checkInDate)
    .subtract(cancellationPeriod, cancellationPeriodUnitTime === 'HOUR' ? 'hours' : 'days')
    .format(
      opts.templateTicket ? 'dddd, DD/MM/YYYY'
        : cancellationPeriodUnitTime === 'HOUR'
          ? 'DD/MM/YYYY HH:mm' : 'DD/MM/YYYY',
    )
  const timeTextString = checkInDate ? `ngày ${date}` : `trước ${time}`
  if (condition === CONDITION_CANCELLATION.NO_CANCELLATION) {
    notes.push({
      label: 'Không hoàn hủy',
      value: false,
      note: opts.templateTicket
        ? `Trước 12:00 PM ngày ${date} sẽ bị tính phí <strong class="fw-700">${netTotal}</strong>/phòng`
        : '✖ Không được hoàn hủy',
    })
  } else if (condition === CONDITION_CANCELLATION.CANCELLATION_CHARGE) {
    const amountFormatted = formatCurrency(amount || 0) || ''
    const unit = unitType === 'PERCENTAGE' ? '%' : ' VND'
    const amountText = amountFormatted ? `${amountFormatted}${unit}` : ''
    notes.push({
      label: `Phí hoàn hủy ${amountText}`,
      value: null,
      note: opts.templateTicket
        ? `Trước 12:00 PM ngày ${date} sẽ <strong class="fw-700"> ${amountText} </strong>/phòng\nTrước 12:00 PM ngày ${checkinDateFormatted} sẽ bị tính phí <strong class="fw-700">${netTotal}</strong>/phòng`
        : `✔ Trước ${timeTextString}: <strong class="fw-700">${amountText}</strong>/phòng.
        ${opts?.shortText ? '' : `\n✖ Từ ${timeTextString} đến ngày nhận phòng: Phí hủy <strong class="fw-700">${netTotal} VND</strong>/phòng.`}
      `,
    })
  } else if (condition === CONDITION_CANCELLATION.FREE_CANCELLATION) {
    notes.push({
      label: `Miễn phí hoàn hủy trước ${timeTextString}`,
      value: true,
      note: opts.templateTicket
        ? `Trước 12:00 PM ngày ${date} sẽ <strong class="fw-700"> Miễn phí huỷ </strong>\nTrước 12:00 PM ngày ${checkinDateFormatted} sẽ bị tính phí <strong class="fw-700">${netTotal}</strong>/phòng`
        : `✔ Trước ${timeTextString}: <strong class="fw-700"> Miễn phí huỷ </strong>.
        ${opts?.shortText ? '' : `\n✖ Từ ${timeTextString} đến ngày nhận phòng: Phí hủy <strong class="fw-700">${netTotal} VND</strong>/phòng.`}
      `,
    })
  } else {
    notes.push({ label: condition, value: null, note: '' })
  }
  return notes
}````

